// NOLA — VAPI Tool Handler
// Handles inbound tool calls from VAPI voice assistant.
// All responses must be plain text — no markdown, no bullet points.
// Tool calls must be responded to within ~20 seconds.
//
// Required env vars:
//   VAPI_SERVER_SECRET  (optional — set to validate inbound x-vapi-secret header)
//   UPS_HOST, UPS_PORT
//   NETDATA_HOSTS  (format: name1:http://ip:port,name2:http://ip:port)
//   PROMETHEUS_URL
//   SSH_ALLOWED_HOSTS, SSH_HOST_<NAME>, SSH_USER_<NAME>
//   N8N_WEBHOOK_BASE_URL  (used to call run_command sub-webhook)

// ── VAPI Server Secret validation ────────────────────────────────
// Set VAPI_SERVER_SECRET in .env and configure the same value as
// "Server Secret" in your VAPI assistant settings.
// VAPI sends it as the x-vapi-secret header on every inbound request.
const VAPI_SERVER_SECRET = process.env.VAPI_SERVER_SECRET || '';
if (VAPI_SERVER_SECRET) {
  const headers = $input.first().json.headers || {};
  const incoming = headers['x-vapi-secret'] || '';
  if (incoming !== VAPI_SERVER_SECRET) {
    throw new Error('Unauthorized: VAPI secret mismatch');
  }
}

const net  = require('net');
const http = require('http');
const { URL } = require('url');

// ── Host map from NETDATA_HOSTS env var ───────────────────────────
const NETDATA_HOST_MAP = {};
(process.env.NETDATA_HOSTS || '').split(',').forEach(h => {
  const colonIdx = h.indexOf(':http');
  if (colonIdx > 0) {
    NETDATA_HOST_MAP[h.slice(0, colonIdx).trim().toLowerCase()] = 'http' + h.slice(colonIdx + 1).trim();
  }
});

const UPS_HOST       = process.env.UPS_HOST  || '';
const UPS_PORT       = parseInt(process.env.UPS_PORT || '3551');
const PROMETHEUS_URL = process.env.PROMETHEUS_URL || '';
const RUN_CMD_URL    = (process.env.N8N_WEBHOOK_BASE_URL || 'http://n8n:5678') + '/webhook/nola-run-command';

// ── HTTP helpers ──────────────────────────────────────────────────
function httpGet(url, ms = 8000) {
  return new Promise((resolve, reject) => {
    const req = http.get(url, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch(e) { reject(new Error('JSON parse error: ' + e.message)); }
      });
    });
    req.on('error', reject);
    req.setTimeout(ms, () => { req.destroy(); reject(new Error('timeout')); });
  });
}

function httpPost(url, body, ms = 20000) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify(body);
    const u = new URL(url);
    const req = http.request({
      hostname: u.hostname, port: u.port || 80,
      path: u.pathname + u.search, method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) }
    }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch(e) { resolve({ raw: data }); }
      });
    });
    req.on('error', reject);
    req.setTimeout(ms, () => { req.destroy(); reject(new Error('timeout')); });
    req.write(payload);
    req.end();
  });
}

// ── Tool: get_ups_status ──────────────────────────────────────────
async function getUpsStatus() {
  if (!UPS_HOST) return 'UPS host not configured.';
  const raw = await new Promise((resolve, reject) => {
    const client = net.createConnection({ host: UPS_HOST, port: UPS_PORT }, () => {
      const cmd = 'status';
      const buf = Buffer.alloc(2 + cmd.length);
      buf.writeUInt16BE(cmd.length, 0);
      buf.write(cmd, 2);
      client.write(buf);
    });
    let rxBuf = Buffer.alloc(0), chunks = '';
    client.on('data', data => {
      rxBuf = Buffer.concat([rxBuf, data]);
      while (rxBuf.length >= 2) {
        const len = rxBuf.readUInt16BE(0);
        if (len === 0) { client.destroy(); resolve(chunks); return; }
        if (rxBuf.length < 2 + len) break;
        chunks += rxBuf.slice(2, 2 + len).toString('utf8');
        rxBuf = rxBuf.slice(2 + len);
      }
    });
    client.on('error', reject);
    client.setTimeout(5000, () => { client.destroy(); reject(new Error('UPS timeout')); });
  });
  const kv = {};
  for (const line of raw.split('\n')) {
    const m = line.match(/^(\w+)\s*:\s*(.+)$/);
    if (m) kv[m[1]] = m[2].trim();
  }
  const name    = kv.UPSNAME  || 'UPS';
  const status  = kv.STATUS   || 'UNKNOWN';
  const battery = parseFloat(kv.BCHARGE)  || 0;
  const load    = parseFloat(kv.LOADPCT)  || 0;
  const runtime = parseFloat(kv.TIMELEFT) || 0;
  const voltage = parseFloat(kv.LINEV)    || 0;
  return `${name}: ${status}. Battery ${battery} percent. Load ${load} percent. Runtime ${runtime.toFixed(0)} minutes. Line voltage ${voltage} volts.`;
}

// ── Tool: get_netdata_metrics ─────────────────────────────────────
async function getNetdataMetrics(host) {
  const baseUrl = NETDATA_HOST_MAP[host.toLowerCase().trim()] || Object.values(NETDATA_HOST_MAP)[0];
  if (!baseUrl) return 'No Netdata hosts configured.';
  function parse(data) {
    if (!data?.data?.length) return {};
    const labels = data.labels.slice(1), vals = data.data[0].slice(1), out = {};
    labels.forEach((l, i) => { out[l] = vals[i]; });
    return out;
  }
  const [cpu, ram, uptime] = await Promise.all([
    httpGet(`${baseUrl}/api/v1/data?chart=system.cpu&after=-60&points=1&format=json`),
    httpGet(`${baseUrl}/api/v1/data?chart=system.ram&after=-60&points=1&format=json`),
    httpGet(`${baseUrl}/api/v1/data?chart=system.uptime&after=-60&points=1&format=json`),
  ]);
  const cpuPct = parseFloat(Object.values(parse(cpu)).reduce((a, b) => a + (b || 0), 0).toFixed(1));
  const ramDims = parse(ram);
  const ramUsed  = Math.abs(ramDims.used  || ramDims.active || 0);
  const ramTotal = Object.values(ramDims).reduce((a, b) => a + Math.abs(b || 0), 0);
  const ramPct   = ramTotal > 0 ? parseFloat((ramUsed / ramTotal * 100).toFixed(1)) : 0;
  const uptimeDims = parse(uptime);
  const uptimeSec  = uptimeDims.uptime ?? Object.values(uptimeDims)[0] ?? 0;
  const uptimeHours = parseFloat((uptimeSec / 3600).toFixed(1));
  return `${host}: CPU ${cpuPct} percent. RAM ${ramPct} percent used. Uptime ${uptimeHours} hours.`;
}

// ── Tool: query_prometheus ────────────────────────────────────────
async function queryPrometheus(query) {
  if (!PROMETHEUS_URL) return 'Prometheus URL not configured.';
  let q = query || 'up';
  const data = await httpGet(`${PROMETHEUS_URL}/api/v1/query?query=${encodeURIComponent(q)}`);
  const result = data.data?.result || [];
  if (result.length === 0) return `No results for: ${q}`;
  return result.slice(0, 6).map(r => {
    const m = r.metric || {};
    const instance = m.instance || m.job || 'unknown';
    const val = r.value ? r.value[1] : '?';
    return `${instance}: ${val}`;
  }).join('. ');
}

// ── Tool: run_command ─────────────────────────────────────────────
async function runCommand(host, command) {
  // Delegates to the run_command sub-workflow for safety checks + SSH routing
  const data = await httpPost(RUN_CMD_URL, { host, command }, 20000);
  return data.output || data.stdout || data.result || (data.error ? `Error: ${data.error}` : JSON.stringify(data).slice(0, 200));
}

// ── Tool: get_amp_status / control_amp_server ─────────────────────
async function controlAmpServer(action, server) {
  const AMP_HOST = process.env.AMP_HOST;
  const AMP_PORT = parseInt(process.env.AMP_PORT || '8080');
  const AMP_USER = process.env.AMP_USER || 'admin';
  const AMP_PASS = process.env.AMP_PASSWORD || '';
  if (!AMP_HOST) return 'AMP game panel not configured. Set AMP_HOST, AMP_PORT, AMP_USER, AMP_PASSWORD.';

  function ampPost(path, body, timeout = 20000) {
    return new Promise((resolve, reject) => {
      const payload = JSON.stringify(body);
      const req = http.request({
        hostname: AMP_HOST, port: AMP_PORT,
        path: `/API/${path}`, method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'Content-Length': Buffer.byteLength(payload) }
      }, res => {
        let data = '';
        res.on('data', c => data += c);
        res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ raw: data }); } });
      });
      req.on('error', reject);
      req.setTimeout(timeout, () => { req.destroy(); reject(new Error('AMP timeout')); });
      req.write(payload); req.end();
    });
  }

  const login = await ampPost('Core/Login', { username: AMP_USER, password: AMP_PASS, token: '', rememberMe: false });
  const sessionID = login.sessionID;
  if (!sessionID) return 'AMP login failed. Check AMP_USER and AMP_PASSWORD.';

  const instancesResp = await ampPost('ADSModule/GetInstances', { SESSIONID: sessionID });
  const instances = [];
  for (const t of (Array.isArray(instancesResp) ? instancesResp : []))
    for (const i of (t.AvailableInstances || []))
      if (i.Module !== 'ADS') instances.push(i);

  const act = (action || 'status').toLowerCase();
  const q   = (server || '').toLowerCase().replace(/[^a-z0-9]/g, '');

  if (act === 'status' || act === 'list' || !q) {
    return 'Game servers: ' + instances.map(i =>
      `${i.FriendlyName}: ${i.Running ? `running with ${i.Metrics?.Active_Users?.RawValue ?? 0} players` : 'stopped'}`
    ).join('. ');
  }

  const inst = instances.find(i => {
    const n = i.InstanceName.toLowerCase().replace(/[^a-z0-9]/g, '');
    const f = i.FriendlyName.toLowerCase().replace(/[^a-z0-9]/g, '');
    return n.includes(q) || f.includes(q);
  });
  if (!inst) return `Server not found: ${server}. Available: ${instances.map(i => i.FriendlyName).join(', ')}.`;

  const endpoints = { start: 'ADSModule/StartInstance', stop: 'ADSModule/StopInstance', restart: 'ADSModule/RestartInstance' };
  if (!endpoints[act]) return `Unknown action: ${act}. Use start, stop, restart, or status.`;

  try {
    await ampPost(endpoints[act], { SESSIONID: sessionID, InstanceName: inst.InstanceName }, act === 'start' ? 45000 : 15000);
  } catch(e) {
    return act === 'start' ? `${inst.FriendlyName}: starting up, this may take a moment.` : `Error: ${e.message}`;
  }
  return `${inst.FriendlyName}: ${act} complete.`;
}

// ── Dispatch all tool calls ───────────────────────────────────────
const body = $input.first().json.body || $input.first().json;
const msg  = body.message || body;
const toolCallList = msg.toolCallList || msg.tool_calls || [];

if (toolCallList.length === 0) {
  return [{ json: { results: [] } }];
}

const results = await Promise.all(toolCallList.map(async (toolCall) => {
  const toolCallId = toolCall.id;
  const toolName   = toolCall.function?.name || toolCall.name;
  let toolArgs = {};
  try { toolArgs = JSON.parse(toolCall.function?.arguments || '{}'); } catch(e) {}

  let result;
  try {
    switch (toolName) {
      case 'get_ups_status':
        result = await getUpsStatus();
        break;
      case 'get_netdata_metrics':
        result = await getNetdataMetrics(toolArgs.host || Object.keys(NETDATA_HOST_MAP)[0] || 'host1');
        break;
      case 'query_prometheus':
        result = await queryPrometheus(toolArgs.query || 'up');
        break;
      case 'run_command':
        result = await runCommand(toolArgs.host, toolArgs.command);
        break;
      case 'control_amp_server':
      case 'get_amp_status':
        result = await controlAmpServer(toolArgs.action || 'status', toolArgs.server || '');
        break;
      default:
        result = `Unknown tool: ${toolName}`;
    }
  } catch(e) {
    result = `${toolName} error: ${e.message}`;
  }

  return { toolCallId, result: String(result) };
}));

return [{ json: { results } }];
